import socket

def scan_ports(host, port_range):
    """Scan a range of ports on a host."""
    open_ports = []
    for port in port_range:
        sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        sock.settimeout(1)
        if sock.connect_ex((host, port)) == 0:
            open_ports.append(port)
        sock.close()
    return open_ports

