def audit_ssh_config(config_text):
    results = []
    checks = {
        'PermitRootLogin': ('no', 'Root login should be disabled'),
        'PasswordAuthentication': ('no', 'Use key-based auth instead'),
        'Port': ('!22', 'Change default SSH port'),
        'MaxAuthTries': ('3', 'Limit authentication attempts'),
    }
    lines = {}
    for line in config_text.strip().split('\n'):
        if line.strip() and not line.startswith('#'):
            parts = line.split()
            if len(parts) >= 2:
                lines[parts[0]] = parts[1]

    for key, (expected, reason) in checks.items():
        actual = lines.get(key, 'NOT SET')
        if expected.startswith('!'):
            passed = actual != expected[1:]
        else:
            passed = actual.lower() == expected.lower()
        status = '✅ PASS' if passed else '❌ FAIL'
        results.append(f'{status}: {key} = {actual} ({reason})')
    return results

