import socket

SERVICE_BANNERS = {
    22: 'SSH', 80: 'HTTP', 443: 'HTTPS', 21: 'FTP',
    25: 'SMTP', 53: 'DNS', 3306: 'MySQL', 5432: 'PostgreSQL',
    6379: 'Redis', 27017: 'MongoDB', 8080: 'HTTP-Proxy',
    8443: 'HTTPS-Alt', 3389: 'RDP', 5900: 'VNC'
}

def discover_services(host, ports=None):
    if ports is None:
        ports = SERVICE_BANNERS.keys()
    services = []
    for port in ports:
        sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        sock.settimeout(1)
        if sock.connect_ex((host, port)) == 0:
            name = SERVICE_BANNERS.get(port, 'Unknown')
            services.append({'port': port, 'service': name, 'status': 'open'})
        sock.close()
    return services

