import hashlib, os, json

class FileIntegrityMonitor:
    def __init__(self, baseline_path='fim_baseline.json'):
        self.baseline_path = baseline_path
        self.baseline = {}

    def hash_file(self, filepath):
        sha = hashlib.sha256()
        with open(filepath, 'rb') as f:
            for chunk in iter(lambda: f.read(8192), b''):
                sha.update(chunk)
        return sha.hexdigest()

    def create_baseline(self, directory):
        self.baseline = {}
        for root, dirs, files in os.walk(directory):
            for fname in files:
                fpath = os.path.join(root, fname)
                try:
                    self.baseline[fpath] = {'hash': self.hash_file(fpath), 'size': os.path.getsize(fpath)}
                except (PermissionError, OSError): pass
        with open(self.baseline_path, 'w') as f:
            json.dump(self.baseline, f, indent=2)
        print(f'Baseline: {len(self.baseline)} files registered')

    def check(self, directory):
        changes = {'modified':[], 'added':[], 'deleted':[]}
        current = set()
        for root, dirs, files in os.walk(directory):
            for fname in files:
                fpath = os.path.join(root, fname)
                current.add(fpath)
                try:
                    h = self.hash_file(fpath)
                    if fpath in self.baseline:
                        if h != self.baseline[fpath]['hash']:
                            changes['modified'].append(fpath)
                    else:
                        changes['added'].append(fpath)
                except (PermissionError, OSError): pass
        for fpath in self.baseline:
            if fpath not in current:
                changes['deleted'].append(fpath)
        return changes

