class HealthCheck:
    def __init__(self):
        self.results = []

    def check_password_files(self):
        # Simulate checking /etc/shadow permissions
        self.results.append({'check':'Password file permissions','status':'PASS','detail':'Restricted access confirmed'})

    def check_open_ports(self):
        import socket
        dangerous = {23:'Telnet',3389:'RDP',5900:'VNC'}
        for port, name in dangerous.items():
            s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
            s.settimeout(0.3)
            if s.connect_ex(('127.0.0.1', port)) == 0:
                self.results.append({'check':f'Port {port} ({name})','status':'FAIL','detail':f'{name} is exposed!'})
            else:
                self.results.append({'check':f'Port {port} ({name})','status':'PASS','detail':'Not exposed'})
            s.close()

    def check_temp_files(self):
        tmp = '/tmp'
        if os.path.exists(tmp):
            suspicious = [f for f in os.listdir(tmp) if f.endswith(('.sh','.py','.exe'))]
            if suspicious:
                self.results.append({'check':'Temp directory','status':'WARN','detail':f'Suspicious files: {suspicious[:3]}'})
            else:
                self.results.append({'check':'Temp directory','status':'PASS','detail':'No suspicious files'})

    def run_all(self):
        print(f'=== SECURITY HEALTH CHECK ===')
        print(f'Time: {datetime.now():%Y-%m-%d %H:%M:%S}')
        self.check_password_files()
        self.check_open_ports()
        self.check_temp_files()

        icons = {'PASS':'✅','FAIL':'🚨','WARN':'⚠️'}
        for r in self.results:
            print(f'  {icons.get(r["status"],"?")} {r["check"]}: {r["detail"]}')

        fails = sum(1 for r in self.results if r['status']=='FAIL')
        warns = sum(1 for r in self.results if r['status']=='WARN')
        total = len(self.results)
        health = 'HEALTHY' if fails==0 and warns==0 else 'AT RISK' if fails==0 else 'CRITICAL'
        print(f'\nOverall: {health} ({total-fails-warns}/{total} passed, {warns} warnings, {fails} failures)')

