def monitor_critical(crit,bl):
    import hashlib,os; print('=== CRITICAL FILE MONITOR ===')
    alerts=0
    for fp in crit:
        if not os.path.exists(fp):
            print(f'  🚨 {fp}: MISSING!'); alerts+=1; continue
        sha=hashlib.sha256()
        with open(fp,'rb') as f:
            for c in iter(lambda:f.read(8192),b''): sha.update(c)
        cur=sha.hexdigest()
        if cur!=bl.get(fp,''):
            print(f'  🚨 {fp}: CHANGED (hash mismatch)'); alerts+=1
